import{_ as r,c as d,o as a,ag as o}from"./chunks/framework.XjE0kKti.js";const e="/gatewayweb/docs/assets/hub0006-list.-c401_Up.png",n="/gatewayweb/docs/assets/hub0006-row-menu.BPGogxxv.png",p=JSON.parse('{"title":"权限资源管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0006.md","filePath":"modules/hub0006.md","lastUpdated":1776841524000}'),s={name:"modules/hub0006.md"};function h(l,t,i,g,b,c){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="权限资源管理" tabindex="-1">权限资源管理 <a class="header-anchor" href="#权限资源管理" aria-label="Permalink to &quot;权限资源管理&quot;">​</a></h1><p>本页维护控制台侧栏、菜单、按钮与接口等在权限体系中可引用的<strong>资源目录</strong>。资源以树形结构组织，供「角色管理」中的 <strong>角色授权</strong> 勾选使用。当前界面以<strong>查询与查看</strong>为主，便于核对路由、层级与启用状态，避免误改内置目录。</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>权限资源</strong>回答的是「系统里有哪些可被授权的点」：</p><ul><li><strong>树形目录</strong>：父节点多为分组或上级模块，子节点为具体页面、菜单或更细粒度项；展开/折叠箭头用于浏览层级。</li><li><strong>与角色的关系</strong>：角色不直接写死菜单，而是通过授权关联到资源 ID；资源变更会影响授权树的展示与生效范围（具体以后端策略为准）。</li><li><strong>内置与自定义</strong>：内置项通常随产品发布；自定义项用于租户扩展。修改内置资源前建议评估对全租户菜单与权限的影响。</li></ul><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>系统设置</strong> → <strong>权限资源管理</strong>。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><ol><li><strong>筛选与操作区</strong>：按名称、编码、类型等条件过滤；提供 <strong>查看详情</strong>、<strong>查询</strong>、<strong>重置</strong>。</li><li><strong>资源树表</strong>：整表以树展示，无分页；通过行前的展开图标逐层打开子资源。</li></ol><p><img src="'+e+'" alt="权限资源管理：树表与筛选"></p><hr><h2 id="查找资源" tabindex="-1">查找资源 <a class="header-anchor" href="#查找资源" aria-label="Permalink to &quot;查找资源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>资源名称</td><td>按展示名称检索。</td></tr><tr><td>资源编码</td><td>按业务或程序侧使用的编码检索。</td></tr><tr><td>资源类型</td><td>全部，或限定为 <strong>模块</strong>、<strong>菜单</strong>、<strong>按钮</strong>、<strong>接口</strong> 之一。</td></tr><tr><td>状态</td><td>全部、启用或禁用。</td></tr><tr><td>类型（内置标记）</td><td>全部、内置或自定义。</td></tr></tbody></table><p>设置条件后点击 <strong>查询</strong>；<strong>重置</strong> 会清空筛选并重新加载默认视图。</p><hr><h2 id="列表字段说明" tabindex="-1">列表字段说明 <a class="header-anchor" href="#列表字段说明" aria-label="Permalink to &quot;列表字段说明&quot;">​</a></h2><p>常见列包括：</p><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>资源ID</td><td>资源的唯一标识，授权树与接口中通常以此为主键引用。</td></tr><tr><td>资源名称</td><td>在列表与授权树中展示的名称。</td></tr><tr><td>资源编码</td><td>便于脚本或配置引用的稳定编码，常与资源 ID 一致或成对出现。</td></tr><tr><td>资源类型</td><td>模块、菜单、按钮、接口等；用于区分页面入口与接口类权限。若数据中存在其它类型值，以界面实际标签为准。</td></tr><tr><td>资源路径</td><td>前端路由或 API 路径等业务含义上的定位信息（菜单路径或接口路径）。</td></tr><tr><td>请求方法</td><td>对接口类资源常见（如 GET、POST）；非接口类可能为空。</td></tr><tr><td>层级</td><td>在树中的深度，便于理解父子关系。</td></tr><tr><td>排序</td><td>控制同层级下的展示顺序，影响侧栏或菜单排列。</td></tr><tr><td>状态</td><td>启用 / 禁用；禁用后一般不应再被授权使用（生效规则以后端为准）。</td></tr><tr><td>类型（表格列）</td><td>内置 / 自定义。</td></tr><tr><td>活动标记</td><td>活动 / 非活动。</td></tr><tr><td>创建与修改信息</td><td>审计字段，用于追溯变更。</td></tr><tr><td>描述</td><td>资源的补充说明。</td></tr></tbody></table><hr><h2 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>打开只读详情弹窗。需先<strong>单击选中</strong>表格中的某一行（或按产品规则选定当前行）；未选中时界面会提示先选择资源。</td></tr><tr><td><strong>查询</strong></td><td>按当前筛选条件刷新树表数据。</td></tr><tr><td><strong>重置</strong></td><td>清空筛选条件并重新加载。</td></tr></tbody></table><hr><h2 id="行右键菜单" tabindex="-1">行右键菜单 <a class="header-anchor" href="#行右键菜单" aria-label="Permalink to &quot;行右键菜单&quot;">​</a></h2><p>在任意资源行上右键，可快速：</p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据</strong></td><td>将整行信息复制到剪贴板，便于写工单或对照配置。</td></tr><tr><td><strong>复制单元格</strong></td><td>仅复制当前单元格内容。</td></tr><tr><td><strong>查看详情</strong></td><td>与工具栏「查看详情」等价，针对当前行打开只读详情。</td></tr></tbody></table><p><img src="'+n+'" alt="权限资源管理：行右键菜单"></p><hr><h2 id="查看详情弹窗" tabindex="-1">查看详情弹窗 <a class="header-anchor" href="#查看详情弹窗" aria-label="Permalink to &quot;查看详情弹窗&quot;">​</a></h2><p>详情以多页签组织，常见分组包括：</p><ul><li><strong>基本信息</strong>：资源 ID、名称、编码、类型、路径、请求方法、显示名称、图标、描述、状态、内置标记、活动标记、备注等。</li><li><strong>层级关系</strong>：父资源 ID、资源层级、排序顺序等，用于理解该节点在树中的位置。</li><li><strong>其他信息</strong>：创建/修改时间与人、版本号等只读审计字段。</li></ul><p>查看模式下不会提交保存；若你所在环境后续开放了新增/编辑入口，仍以界面实际按钮为准。</p><hr><h2 id="与「角色管理」的协作" tabindex="-1">与「角色管理」的协作 <a class="header-anchor" href="#与「角色管理」的协作" aria-label="Permalink to &quot;与「角色管理」的协作&quot;">​</a></h2><ol><li>在本页确认资源 ID、路径与层级是否正确、是否为启用状态。</li><li>在 <strong>角色管理</strong> 中打开某角色的 <strong>角色授权</strong>，在树中勾选对应资源。</li><li>再将该角色分配给 <strong>用户管理</strong> 中的用户。</li></ol><p>若授权树中缺少某菜单，通常应回到本页核对该资源是否存在、是否禁用、父子关系是否正确。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>提示先选择资源</td><td>使用工具栏「查看详情」前需先在树表中单击选中目标行。</td></tr><tr><td>列表与侧栏不一致</td><td>可能存在缓存或多环境配置差异；核对资源路径与启用状态，必要时重新登录或联系运维刷新权限缓存。</td></tr><tr><td>某节点类型显示为英文代码</td><td>数据中的类型值可能超出常见四类枚举，以数据库或后端定义为准并在文档中备案。</td></tr></tbody></table>',41)])])}const m=r(s,[["render",h]]);export{p as __pageData,m as default};
